import { useEffect, useCallback } from 'react';

const BACKSPACE = 'deleteContentBackward';
const DELETE = 'deleteContentForward';

/** @typedef {import('./hooks').UseMaskProps} UseMaskProps */

/**
 * @param {import('react').RefObject<HTMLDivElement | null>} inputRef
 * @param {UseMaskProps} maskProps
 */
const useMask = (inputRef, { onChange, onInput, maskOptions }) => {
  const applyMask = useCallback((/** @type {InputEvent | undefined} */ event, /** @type {string} */ inputValue) => {
    let cursor = 0;
    const result = [];
    // Pre-process the input value if a pre-processing function is defined
    const newValue = maskOptions.preProcess ? maskOptions.preProcess(inputValue) : inputValue;
    const isDelete = (event?.inputType === BACKSPACE || event?.inputType === DELETE);
    // Iterate over each character in the mask

    for (let i = 0; i < maskOptions.mask.length; i += 1) {
      const maskChar = maskOptions.mask[i];

      // Stop if the end of the input value is reached
      if (cursor >= newValue.length) {
        if (maskOptions.eager && !maskOptions.tokens[maskChar] && !isDelete) {
          result.push(maskChar);
        }
        break;
      }

      if (maskOptions.tokens[maskChar]?.multiple || maskOptions.tokens[maskChar]) {
        while (cursor < newValue.length) {
          const match = newValue[cursor].match(maskOptions.tokens[maskChar].pattern);
          if (match) {
            result.push(match[0]);
            cursor += 1;
            // Stop after the first match if multiple matches are not allowed
            if (!maskOptions.tokens[maskChar].multiple) break;
          } else {
            // Stop if not match if multiple matches are allowed
            if (maskOptions.tokens[maskChar].multiple && newValue[cursor] === maskOptions.mask[i + 1]) break;
            cursor += 1;
          }
        }
      } else {
        // If the mask character is a fixed character

        // Avoid adding fixed characters if the input is a backspace or delete and the input is at the current position
        if (isDelete && newValue.length === i) {
          break;
        }

        // If eager flag is false, avoid automatically adding the fixed character
        // and stop if the next character in the input doesn't match the fixed character
        if (!maskOptions.eager && maskChar !== newValue[cursor]) {
          break;
        }

        // Add the fixed character to the result and advance the cursor if the eager flag is false
        // or the next character in the input matches the fixed character
        if (maskChar === newValue[cursor]) cursor += 1;
        result.push(maskChar);
      }
    }

    let maskedValue = result.join('');

    // Post-process the masked value if a post-processing function is defined
    if (maskOptions.postProcess) maskedValue = maskOptions.postProcess(maskedValue);

    return maskedValue;
  }, [maskOptions]);

  /**
   * @param {HTMLInputElement} input
   * @param {string} value
   */
  const changeInputValue = (input, value) => {
    // We're faking that the setValue was triggered natively
    const objectPrototype = Object.getPrototypeOf(input);
    const { set: prototypeValueSetter } = Object.getOwnPropertyDescriptor(objectPrototype, 'value') || {};
    prototypeValueSetter?.call(input, value);
  };

  const handleInputChange = useCallback((/** @type {Event} */ event) => {
    const inputElement = inputRef?.current?.querySelector('input');
    let cursorPosition = inputElement?.selectionStart || 0;
    const value = /** @type {HTMLInputElement} */(event.target)?.value || '';
    const maskedValue = applyMask(/** @type {InputEvent} */(event), value);

    // we change the value to undefined so when react compares prev and next values
    // they are different and it triggers the onchange event

    // @ts-expect-error undefined is not assignable to string but we need to change the value
    /** @type {HTMLInputElement} */ (inputElement).value = undefined;
    // @ts-expect-error undefined is not assignable to string but we need to change the value
    /** @type {HTMLInputElement} */(event.target).value = undefined;
    // next we call the native value setter to change the value so react thinks it was changed by the user
    changeInputValue(/** @type {HTMLInputElement} */ (inputElement), maskedValue);

    if (typeof onInput === 'function') {
      onInput(/** @type {import('react').ChangeEvent<HTMLInputElement>} */ (/** @type {unknown} */ (event)));
    }
    if (typeof onChange === 'function') {
      onChange(/** @type {import('react').ChangeEvent<HTMLInputElement>} */ (/** @type {unknown} */ (event)));
    }

    // Position cursor

    const diffLength = maskedValue.length - value.length;
    cursorPosition += (diffLength < 0 ? 0 : diffLength);
    if (inputElement) {
      inputElement.selectionStart = cursorPosition;
      inputElement.selectionEnd = cursorPosition;
    }
  }, [onChange, onInput, applyMask, inputRef]);

  useEffect(() => {
    if (!inputRef.current) return;

    const inputElement = inputRef?.current?.querySelector('input');
    const inputValue = inputElement?.value;

    if (inputElement) inputElement.addEventListener('input', handleInputChange);

    if (inputValue) {
      const maskedValue = applyMask(undefined, inputValue);
      changeInputValue(inputElement, maskedValue);

      const changeEvent = new Event('change', { bubbles: true });
      inputElement.dispatchEvent(changeEvent);

      // This code is for inline edit, since it uses a p tag to display the value, we need to change its textContent
      // in order to expand the input width
      const isInlineEdit = Array.from(inputRef.current.classList).some(className => className.includes('inline-edit'));
      if (isInlineEdit) {
        const inlineEditParagraph = inputRef?.current?.querySelector('p');
        if (inlineEditParagraph) {
          inlineEditParagraph.textContent = maskedValue;
        }
      }
    }

    return () => {
      if (inputElement) inputElement.removeEventListener('input', handleInputChange);
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [inputRef, handleInputChange]);
};

export default useMask;
